package apikeys

import (
	"context"
	"encoding/json"
	"net/http"
	"time"

	"github.com/google/uuid"
	"github.com/harusame0616/ijuku/apps/api/internal/db"
	libauth "github.com/harusame0616/ijuku/apps/api/lib/auth"
	"github.com/harusame0616/ijuku/apps/api/lib/response"
	"github.com/jackc/pgx/v5/pgtype"
)

type listApiKeysQuery interface {
	ListApiKeysByUserID(ctx context.Context, userid pgtype.UUID) ([]db.ListApiKeysByUserIDRow, error)
}

type ListApiKeysHandler struct {
	query listApiKeysQuery
}

func NewListApiKeysHandler(q listApiKeysQuery) *ListApiKeysHandler {
	return &ListApiKeysHandler{query: q}
}

type ApiKeyListItem struct {
	ApiKeyID  string  `json:"apiKeyId"`
	Suffix    string  `json:"suffix"`
	CreatedAt string  `json:"createdAt"`
	ExpiredAt *string `json:"expiredAt"`
}

type ListApiKeysResponse struct {
	ApiKeys []ApiKeyListItem `json:"apiKeys"`
}

func (h *ListApiKeysHandler) ListApiKeysHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	userIDStr, ok := libauth.UserIDFromContext(r.Context())
	if !ok {
		response.WriteErrorResponse(w, http.StatusUnauthorized, "UNAUTHORIZED", "unauthorized")
		return
	}

	var userID pgtype.UUID
	if err := userID.Scan(userIDStr); err != nil {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "userID must be a valid UUID")
		return
	}

	rows, err := h.query.ListApiKeysByUserID(r.Context(), userID)
	if err != nil {
		response.WriteInternalServerErrorResponse(w)
		return
	}

	items := make([]ApiKeyListItem, 0, len(rows))
	for _, row := range rows {
		items = append(items, ApiKeyListItem{
			ApiKeyID:  uuid.UUID(row.ApikeyID.Bytes).String(),
			Suffix:    row.PlainSuffix,
			CreatedAt: row.CreatedAt.Time.UTC().Format(time.RFC3339),
			ExpiredAt: formatExpiredAt(row.ExpiredAt),
		})
	}

	_ = json.NewEncoder(w).Encode(ListApiKeysResponse{ApiKeys: items})
}

func formatExpiredAt(t pgtype.Timestamptz) *string {
	if !t.Valid || t.InfinityModifier != pgtype.Finite {
		return nil
	}
	formatted := t.Time.UTC().Format(time.RFC3339)
	return &formatted
}

package apikeys_test

import (
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
	"time"

	libauth "github.com/harusame0616/ijuku/apps/api/lib/auth"
	"github.com/harusame0616/ijuku/apps/api/lib/env"
	"github.com/harusame0616/ijuku/apps/api/lib/txrunner"
	"github.com/harusame0616/ijuku/apps/api/lib/uuidutils"
	"github.com/harusame0616/ijuku/apps/api/routes/users/settings/apikeys"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestGenerateApiKeyHandlerMedium(t *testing.T) {
	ctx := context.Background()
	pool, err := pgxpool.New(ctx, env.Require("DATABASE_URL"))
	if err != nil {
		t.Fatalf("DBへの接続に失敗しました: %v", err)
	}
	defer pool.Close()

	handler := apikeys.NewGenerateApiKeyHandler(apikeys.NewGenerateApiKeyUsecase(apikeys.NewApiKeySqrcRepository(), txrunner.NewPgxTransactionRunner(pool)))

	newAuthorizedRequest := func(t *testing.T, userID, body string) *http.Request {
		t.Helper()
		r := httptest.NewRequest("POST", "/v1/me/apikeys", strings.NewReader(body))
		if userID != "" {
			r = r.WithContext(libauth.WithUserID(r.Context(), userID))
		}
		return r
	}

	t.Run("認証されていない場合 401 を返す", func(t *testing.T) {
		r := httptest.NewRequest("POST", "/v1/me/apikeys", strings.NewReader("{}"))
		w := httptest.NewRecorder()

		handler.GenerateApiKeyHandler(w, r)

		assert.Equal(t, http.StatusUnauthorized, w.Result().StatusCode)
	})

	t.Run("userId が非 UUID の場合 Input Validation Error を返す", func(t *testing.T) {
		r := newAuthorizedRequest(t, "invalid-uuid", "{}")
		w := httptest.NewRecorder()

		handler.GenerateApiKeyHandler(w, r)

		var responseBody map[string]any
		json.NewDecoder(w.Result().Body).Decode(&responseBody)
		assert.Equal(t, map[string]any{
			"errorCode": "INPUT_VALIDATION_ERROR",
			"message":   "User ID must be valid UUID",
		}, responseBody)
	})

	t.Run("expiredAt のフォーマットが ISO 8601 フォーマットではない場合 Input Validation Error を返す", func(t *testing.T) {
		r := newAuthorizedRequest(t, "BD30D30D-01A0-4E43-A00D-1E6EB88A1D54", `{"expiredAt": "invalid format"}`)
		w := httptest.NewRecorder()

		handler.GenerateApiKeyHandler(w, r)

		var responseBody map[string]any
		json.NewDecoder(w.Result().Body).Decode(&responseBody)
		assert.Equal(t, map[string]any{
			"errorCode": "INPUT_VALIDATION_ERROR",
			"message":   "expiredAt must be ISO 8601 format",
		}, responseBody)
	})

	t.Run("Body のフォーマットが json フォーマットではない場合 Input Validation Error を返す", func(t *testing.T) {
		r := newAuthorizedRequest(t, "BD30D30D-01A0-4E43-A00D-1E6EB88A1D54", `invalid json`)
		w := httptest.NewRecorder()

		handler.GenerateApiKeyHandler(w, r)

		var responseBody map[string]any
		json.NewDecoder(w.Result().Body).Decode(&responseBody)
		assert.Equal(t, map[string]any{
			"errorCode": "INPUT_VALIDATION_ERROR",
			"message":   "Body must be valid JSON",
		}, responseBody)
	})

	t.Run("API KEY が上限を超えている場合 Apikey Quota Exceeds Limit Error を返す", func(t *testing.T) {
		userID := uuidutils.MustNewUuidString()
		require.NoError(t, insertUser(ctx, pool, userID))
		t.Cleanup(func() {
			cleanupApiKeys(ctx, pool, userID)
			cleanupUser(ctx, pool, userID)
		})
		for i := 0; i < 5; i++ {
			_, err := pool.Exec(ctx, `INSERT INTO apikeys (apikey_id, user_id, key_hash, plain_suffix, expired_at) VALUES ($1, $2, $3, 'suffix', 'infinity')`, uuidutils.MustNewUuidString(), userID, uuidutils.MustNewUuidString())
			require.NoError(t, err)
		}

		r := newAuthorizedRequest(t, userID, "{}")
		w := httptest.NewRecorder()

		handler.GenerateApiKeyHandler(w, r)

		var responseBody map[string]any
		json.NewDecoder(w.Result().Body).Decode(&responseBody)
		assert.Equal(t, map[string]any{
			"errorCode": "APIKEY_QUOTA_EXCEEDS_LIMIT",
			"message":   "Api key quota exceeds limit. Api key quota limit is 5",
		}, responseBody)
	})

	t.Run("API KEY を上限まで登録できる", func(t *testing.T) {
		userID := uuidutils.MustNewUuidString()
		require.NoError(t, insertUser(ctx, pool, userID))
		t.Cleanup(func() {
			cleanupApiKeys(ctx, pool, userID)
			cleanupUser(ctx, pool, userID)
		})
		for i := 0; i < 4; i++ {
			_, err := pool.Exec(ctx, `INSERT INTO apikeys (apikey_id, user_id, key_hash, plain_suffix, expired_at) VALUES ($1, $2, $3, 'suffix', 'infinity')`, uuidutils.MustNewUuidString(), userID, uuidutils.MustNewUuidString())
			require.NoError(t, err)
		}

		r := newAuthorizedRequest(t, userID, "{}")
		w := httptest.NewRecorder()

		handler.GenerateApiKeyHandler(w, r)

		var responseBody map[string]any
		json.NewDecoder(w.Result().Body).Decode(&responseBody)
		assert.Regexp(t, "jukubox_.+", responseBody["apikey"])
	})

	t.Run("expiredAt を指定した場合 API KEY を有効期限付きで登録できる", func(t *testing.T) {
		userID := uuidutils.MustNewUuidString()
		require.NoError(t, insertUser(ctx, pool, userID))
		t.Cleanup(func() {
			cleanupApiKeys(ctx, pool, userID)
			cleanupUser(ctx, pool, userID)
		})

		r := newAuthorizedRequest(t, userID, `{"expiredAt": "2030-01-01T00:00:00Z"}`)
		w := httptest.NewRecorder()

		handler.GenerateApiKeyHandler(w, r)

		var responseBody map[string]any
		json.NewDecoder(w.Result().Body).Decode(&responseBody)
		assert.Regexp(t, "jukubox_.+", responseBody["apikey"])

		var expiredAt time.Time
		require.NoError(t, pool.QueryRow(ctx, `SELECT expired_at FROM apikeys WHERE user_id = $1`, userID).Scan(&expiredAt))
		assert.Equal(t, "2030-01-01T00:00:00Z", expiredAt.UTC().Format(time.RFC3339))
	})
}

package apikeys

import (
	"context"
	"errors"
	"strings"
	"testing"

	"github.com/google/uuid"
	"github.com/jackc/pgx/v5"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

type fakeTransactionRunner struct {
	advisoryLockErr error
}

func (r *fakeTransactionRunner) RunInTransaction(ctx context.Context, f func(tx pgx.Tx) error) error {
	return f(nil)
}

func (r *fakeTransactionRunner) AcquireAdvisoryLock(_ context.Context, _ pgx.Tx, _ int64) error {
	return r.advisoryLockErr
}

type fakeApiKeyRepository struct {
	count     int
	saveErr   error
	savedKey  *hashedApiKey
	saveCalls int
}

func (r *fakeApiKeyRepository) countWithTx(_ context.Context, _ pgx.Tx, _ uuid.UUID) int {
	return r.count
}

func (r *fakeApiKeyRepository) saveWithTx(_ context.Context, _ pgx.Tx, key hashedApiKey) error {
	r.saveCalls++
	if r.saveErr != nil {
		return r.saveErr
	}
	r.savedKey = &key
	return nil
}

func TestGenerateApiKeyUsecaseExecute(t *testing.T) {
	ctx := context.Background()
	userID := uuid.New()

	t.Run("AcquireAdvisoryLock がエラーを返した場合エラーを伝搬する", func(t *testing.T) {
		lockErr := errors.New("lock failed")
		usecase := NewGenerateApiKeyUsecase(
			&fakeApiKeyRepository{},
			&fakeTransactionRunner{advisoryLockErr: lockErr},
		)
		_, err := usecase.Execute(ctx, userID, nil)
		assert.ErrorIs(t, err, lockErr)
	})

	t.Run("API キー数が上限以上の場合 ErrApiKeyCountExceedsLimit を返す", func(t *testing.T) {
		usecase := NewGenerateApiKeyUsecase(
			&fakeApiKeyRepository{count: apiKeyMaxCount},
			&fakeTransactionRunner{},
		)
		_, err := usecase.Execute(ctx, userID, nil)
		assert.ErrorIs(t, err, ErrApiKeyCountExceedsLimit)
	})

	t.Run("saveWithTx がエラーを返した場合エラーを伝搬する", func(t *testing.T) {
		saveErr := errors.New("save failed")
		usecase := NewGenerateApiKeyUsecase(
			&fakeApiKeyRepository{saveErr: saveErr},
			&fakeTransactionRunner{},
		)
		_, err := usecase.Execute(ctx, userID, nil)
		assert.ErrorIs(t, err, saveErr)
	})

	t.Run("正常系では平文 API キーを返し saveWithTx に正しい hashedApiKey が渡される", func(t *testing.T) {
		repo := &fakeApiKeyRepository{}
		usecase := NewGenerateApiKeyUsecase(repo, &fakeTransactionRunner{})

		result, err := usecase.Execute(ctx, userID, nil)
		require.NoError(t, err)
		assert.True(t, strings.HasPrefix(result.Apikey, "jukubox_"))
		require.Equal(t, 1, repo.saveCalls)
		require.NotNil(t, repo.savedKey)
		assert.Equal(t, userID, repo.savedKey.userID)
		assert.Equal(t, result.Apikey[len(result.Apikey)-4:], repo.savedKey.plainApiKeySuffix)
	})
}

