"use client";

import { atom, useAtom, useAtomValue, useSetAtom } from "jotai";
import { type JSX, useState, useTransition } from "react";
import { Button } from "@/components/ui/button";
import { useIsHydrated } from "@/hooks/use-is-hydrated";
import {
  type GenerateApiKeyErrorCode,
  generateApiKey,
} from "./generate-api-key.action";

const errorMessages: Record<GenerateApiKeyErrorCode, string> = {
  UNAUTHORIZED: "認証が切れています。再度ログインしてください。",
  APIKEY_QUOTA_EXCEEDS_LIMIT:
    "API キーの登録上限に達しています。不要なキーを削除してから再度生成してください。",
  APIKEY_LOCK_TIMEOUT:
    "API キーを生成できませんでした。時間をおいて再度お試しください。",
  INTERNAL_ERROR:
    "予期しないエラーが発生しました。時間をおいて再度お試しください。",
};

type CopyState = "idle" | "copied" | "failed";

const generatedAtom = atom<string | null>(null);
const errorCodeAtom = atom<GenerateApiKeyErrorCode | null>(null);

export function GenerateApiKeyTrigger(): JSX.Element {
  const isHydrated = useIsHydrated();
  const [isPending, startTransition] = useTransition();
  const setGenerated = useSetAtom(generatedAtom);
  const setErrorCode = useSetAtom(errorCodeAtom);

  const handleGenerate = (): void => {
    setErrorCode(null);
    startTransition(async () => {
      const result = await generateApiKey();
      if (result.success) {
        setGenerated(result.apiKey);
      } else {
        setGenerated(null);
        setErrorCode(result.code);
      }
    });
  };

  return (
    <Button
      type="button"
      onClick={handleGenerate}
      size="sm"
      disabled={!isHydrated || isPending}
    >
      {isPending ? "生成中..." : "API キー生成"}
    </Button>
  );
}

export function GenerateApiKeyResult(): JSX.Element | null {
  const [generated, setGenerated] = useAtom(generatedAtom);
  const errorCode = useAtomValue(errorCodeAtom);

  if (generated === null && errorCode === null) {
    return null;
  }

  return (
    <div className="flex flex-col gap-4">
      {errorCode !== null && (
        <p
          role="alert"
          className="border-destructive bg-destructive/10 text-destructive border px-4 py-3 text-sm"
        >
          {errorMessages[errorCode]}
        </p>
      )}

      {generated !== null && (
        <GeneratedApiKeyCard
          key={generated}
          apiKey={generated}
          onClose={() => setGenerated(null)}
        />
      )}
    </div>
  );
}

interface GeneratedApiKeyCardProps {
  apiKey: string;
  onClose: () => void;
}

function GeneratedApiKeyCard({
  apiKey,
  onClose,
}: GeneratedApiKeyCardProps): JSX.Element {
  const [copyState, setCopyState] = useState<CopyState>("idle");

  const handleCopy = async (): Promise<void> => {
    try {
      await navigator.clipboard.writeText(apiKey);
      setCopyState("copied");
    } catch {
      setCopyState("failed");
    }
  };

  return (
    <div className="border-primary bg-card flex flex-col gap-3 border px-4 py-4">
      <p className="text-sm">
        API
        キーを生成しました。この画面を閉じると再表示できないため、必ずコピーして安全な場所に保管してください。
      </p>
      <code className="bg-muted block px-3 py-2 font-mono text-sm break-all">
        {apiKey}
      </code>
      <div className="flex items-center gap-3">
        <Button
          type="button"
          variant="secondary"
          onClick={handleCopy}
          size="sm"
        >
          コピー
        </Button>
        <Button type="button" variant="outline" onClick={onClose} size="sm">
          閉じる
        </Button>
        {copyState === "copied" && (
          <span aria-live="polite" className="text-muted-foreground text-sm">
            コピーしました
          </span>
        )}
        {copyState === "failed" && (
          <span aria-live="polite" className="text-destructive text-sm">
            コピーに失敗しました
          </span>
        )}
      </div>
    </div>
  );
}

package apikeys

import (
	"context"
	"encoding/json"
	"errors"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"

	"github.com/google/uuid"
	"github.com/harusame0616/ijuku/apps/api/internal/db"
	libauth "github.com/harusame0616/ijuku/apps/api/lib/auth"
	"github.com/jackc/pgx/v5/pgtype"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

const (
	testUserID  = "00000000-0000-0000-0000-000000000001"
	apikeyIDOne = "11111111-1111-1111-1111-111111111111"
	apikeyIDTwo = "22222222-2222-2222-2222-222222222222"
)

type mockListApiKeysQuery struct {
	rows []db.ListApiKeysByUserIDRow
	err  error
}

func (m *mockListApiKeysQuery) ListApiKeysByUserID(_ context.Context, _ pgtype.UUID) ([]db.ListApiKeysByUserIDRow, error) {
	return m.rows, m.err
}

func newListRequest(t *testing.T, userID string) *http.Request {
	t.Helper()
	req := httptest.NewRequest(http.MethodGet, "/v1/me/settings/apikeys", nil)
	if userID != "" {
		req = req.WithContext(libauth.WithUserID(req.Context(), userID))
	}
	return req
}

func mustUUID(t *testing.T, s string) pgtype.UUID {
	t.Helper()
	parsed, err := uuid.Parse(s)
	require.NoError(t, err)
	return pgtype.UUID{Bytes: parsed, Valid: true}
}

func TestListApiKeysHandler(t *testing.T) {
	t.Run("認証情報が無い場合401を返す", func(t *testing.T) {
		h := NewListApiKeysHandler(&mockListApiKeysQuery{})
		w := httptest.NewRecorder()
		h.ListApiKeysHandler(w, newListRequest(t, ""))
		assert.Equal(t, http.StatusUnauthorized, w.Result().StatusCode)
	})

	t.Run("userIDがUUID形式でない場合400を返す", func(t *testing.T) {
		h := NewListApiKeysHandler(&mockListApiKeysQuery{})
		w := httptest.NewRecorder()
		h.ListApiKeysHandler(w, newListRequest(t, "not-a-uuid"))
		assert.Equal(t, http.StatusBadRequest, w.Result().StatusCode)
	})

	t.Run("DBエラーの場合500を返す", func(t *testing.T) {
		h := NewListApiKeysHandler(&mockListApiKeysQuery{err: errors.New("db error")})
		w := httptest.NewRecorder()
		h.ListApiKeysHandler(w, newListRequest(t, testUserID))
		assert.Equal(t, http.StatusInternalServerError, w.Result().StatusCode)
	})

	t.Run("0件の場合200と空配列を返す", func(t *testing.T) {
		h := NewListApiKeysHandler(&mockListApiKeysQuery{rows: nil})
		w := httptest.NewRecorder()
		h.ListApiKeysHandler(w, newListRequest(t, testUserID))
		assert.Equal(t, http.StatusOK, w.Result().StatusCode)

		var body ListApiKeysResponse
		require.NoError(t, json.NewDecoder(w.Result().Body).Decode(&body))
		assert.Equal(t, []ApiKeyListItem{}, body.ApiKeys)
	})

	t.Run("複数件と無期限が正しくシリアライズされる", func(t *testing.T) {
		createdAt := time.Date(2026, 1, 10, 12, 0, 0, 0, time.UTC)
		expiredAt := time.Date(2027, 1, 10, 12, 0, 0, 0, time.UTC)
		expiredAtStr := "2027-01-10T12:00:00Z"
		h := NewListApiKeysHandler(&mockListApiKeysQuery{
			rows: []db.ListApiKeysByUserIDRow{
				{
					ApikeyID:    mustUUID(t, apikeyIDOne),
					PlainSuffix: "a3f9",
					CreatedAt:   pgtype.Timestamptz{Time: createdAt, Valid: true},
					ExpiredAt:   pgtype.Timestamptz{Time: expiredAt, Valid: true},
				},
				{
					ApikeyID:    mustUUID(t, apikeyIDTwo),
					PlainSuffix: "c5d1",
					CreatedAt:   pgtype.Timestamptz{Time: createdAt, Valid: true},
					ExpiredAt:   pgtype.Timestamptz{InfinityModifier: pgtype.Infinity, Valid: true},
				},
			},
		})
		w := httptest.NewRecorder()
		h.ListApiKeysHandler(w, newListRequest(t, testUserID))
		assert.Equal(t, http.StatusOK, w.Result().StatusCode)

		var body ListApiKeysResponse
		require.NoError(t, json.NewDecoder(w.Result().Body).Decode(&body))
		require.Len(t, body.ApiKeys, 2)

		assert.Equal(t, apikeyIDOne, body.ApiKeys[0].ApiKeyID)
		assert.Equal(t, "a3f9", body.ApiKeys[0].Suffix)
		assert.Equal(t, "2026-01-10T12:00:00Z", body.ApiKeys[0].CreatedAt)
		require.NotNil(t, body.ApiKeys[0].ExpiredAt)
		assert.Equal(t, expiredAtStr, *body.ApiKeys[0].ExpiredAt)

		assert.Equal(t, apikeyIDTwo, body.ApiKeys[1].ApiKeyID)
		assert.Equal(t, "c5d1", body.ApiKeys[1].Suffix)
		assert.Nil(t, body.ApiKeys[1].ExpiredAt)
	})
}

