package apikeys

import (
	"context"
	"errors"
	"testing"

	"github.com/google/uuid"
	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

type mockDeleteApiKeyQuery struct {
	rows int64
	err  error
	got  db.DeleteApiKeyByIDParams
}

func (m *mockDeleteApiKeyQuery) DeleteApiKeyByID(_ context.Context, arg db.DeleteApiKeyByIDParams) (int64, error) {
	m.got = arg
	return m.rows, m.err
}

func TestDeleteApiKeyUsecaseExecute(t *testing.T) {
	ctx := context.Background()
	userID := uuid.New()
	apiKeyID := uuid.New()

	t.Run("クエリがエラーを返した場合エラーを伝搬する", func(t *testing.T) {
		queryErr := errors.New("db error")
		usecase := NewDeleteApiKeyUsecase(&mockDeleteApiKeyQuery{err: queryErr})
		assert.ErrorIs(t, usecase.Execute(ctx, userID, apiKeyID), queryErr)
	})

	t.Run("削除対象が無い場合 ErrApiKeyNotFound を返す", func(t *testing.T) {
		usecase := NewDeleteApiKeyUsecase(&mockDeleteApiKeyQuery{rows: 0})
		assert.ErrorIs(t, usecase.Execute(ctx, userID, apiKeyID), ErrApiKeyNotFound)
	})

	t.Run("削除に成功した場合 nil を返し、 user_id と apikey_id がパラメータに渡る", func(t *testing.T) {
		query := &mockDeleteApiKeyQuery{rows: 1}
		usecase := NewDeleteApiKeyUsecase(query)
		require.NoError(t, usecase.Execute(ctx, userID, apiKeyID))
		assert.Equal(t, [16]byte(userID), query.got.UserID.Bytes)
		assert.Equal(t, [16]byte(apiKeyID), query.got.ApikeyID.Bytes)
	})
}

