import { expect, test as base, vi } from "vitest";
import { render } from "vitest-browser-react";
import { ApiKeysListPresenter } from "./api-keys-list.presenter.client";
import type { DeleteApiKeyResult } from "./delete-api-key.action";

const deleteApiKeyMock = vi.fn<(apiKeyId: string) => Promise<DeleteApiKeyResult>>();

vi.mock("./delete-api-key.action", () => ({
  deleteApiKey: (apiKeyId: string) => deleteApiKeyMock(apiKeyId),
}));

const test = base.extend<{ setup: void }>({
  setup: async ({}, provide) => {
    deleteApiKeyMock.mockReset();
    await provide(undefined as never);
  },
});

test("0 件の場合は空状態メッセージを表示する", async ({ setup: _setup }) => {
  const screen = await render(<ApiKeysListPresenter apiKeys={[]} />);

  await expect
    .element(screen.getByText("API キーがまだ登録されていません。"))
    .toBeInTheDocument();
});

test("複数件の API キーが jukubox_••••<末尾> 形式で表示される", async ({
  setup: _setup,
}) => {
  const screen = await render(
    <ApiKeysListPresenter
      apiKeys={[
        {
          apiKeyId: "id-1",
          suffix: "a3f9",
          createdAt: "2026-01-10T00:00:00Z",
          expiredAt: "2027-01-10T00:00:00Z",
        },
        {
          apiKeyId: "id-2",
          suffix: "b218",
          createdAt: "2026-02-22T00:00:00Z",
          expiredAt: "2027-02-22T00:00:00Z",
        },
      ]}
    />,
  );

  await expect
    .element(screen.getByText("jukubox_••••a3f9"))
    .toBeInTheDocument();
  await expect
    .element(screen.getByText("jukubox_••••b218"))
    .toBeInTheDocument();
});

test("expiredAt が null の場合は『無期限』と表示される", async ({
  setup: _setup,
}) => {
  const screen = await render(
    <ApiKeysListPresenter
      apiKeys={[
        {
          apiKeyId: "id-1",
          suffix: "c5d1",
          createdAt: "2026-04-01T00:00:00Z",
          expiredAt: null,
        },
      ]}
    />,
  );

  await expect.element(screen.getByText("無期限")).toBeInTheDocument();
});

test("disabled=true の場合はテーブルヘッダーが表示され、空状態メッセージは表示されない", async ({
  setup: _setup,
}) => {
  const screen = await render(<ApiKeysListPresenter disabled />);

  await expect.element(screen.getByText("API キー")).toBeInTheDocument();
  await expect
    .element(screen.getByText("API キーがまだ登録されていません。"))
    .not.toBeInTheDocument();
});

test("削除ボタン押下で確認 UI が表示される", async ({ setup: _setup }) => {
  const screen = await render(
    <ApiKeysListPresenter
      apiKeys={[
        {
          apiKeyId: "id-1",
          suffix: "a3f9",
          createdAt: "2026-01-10T00:00:00Z",
          expiredAt: null,
        },
      ]}
    />,
  );

  await screen.getByRole("button", { name: "削除" }).click();

  await expect
    .element(screen.getByText("本当に削除しますか？"))
    .toBeVisible();
});

test("「削除する」を押すと action が呼ばれて確認 UI が閉じる", async ({
  setup: _setup,
}) => {
  deleteApiKeyMock.mockResolvedValue({ success: true });
  const screen = await render(
    <ApiKeysListPresenter
      apiKeys={[
        {
          apiKeyId: "id-1",
          suffix: "a3f9",
          createdAt: "2026-01-10T00:00:00Z",
          expiredAt: null,
        },
      ]}
    />,
  );

  await screen.getByRole("button", { name: "削除" }).click();
  await screen.getByRole("button", { name: "削除する" }).click();

  await expect
    .element(screen.getByText("本当に削除しますか？"))
    .not.toBeInTheDocument();
  expect(deleteApiKeyMock).toHaveBeenCalledWith("id-1");
});

test("「キャンセル」を押すと action は呼ばれず確認 UI が閉じる", async ({
  setup: _setup,
}) => {
  const screen = await render(
    <ApiKeysListPresenter
      apiKeys={[
        {
          apiKeyId: "id-1",
          suffix: "a3f9",
          createdAt: "2026-01-10T00:00:00Z",
          expiredAt: null,
        },
      ]}
    />,
  );

  await screen.getByRole("button", { name: "削除" }).click();
  await screen.getByRole("button", { name: "キャンセル" }).click();

  await expect
    .element(screen.getByText("本当に削除しますか？"))
    .not.toBeInTheDocument();
  expect(deleteApiKeyMock).not.toHaveBeenCalled();
});

test("削除に失敗した場合はエラーメッセージを表示する", async ({
  setup: _setup,
}) => {
  deleteApiKeyMock.mockResolvedValue({
    success: false,
    code: "APIKEY_NOT_FOUND",
  });
  const screen = await render(
    <ApiKeysListPresenter
      apiKeys={[
        {
          apiKeyId: "id-1",
          suffix: "a3f9",
          createdAt: "2026-01-10T00:00:00Z",
          expiredAt: null,
        },
      ]}
    />,
  );

  await screen.getByRole("button", { name: "削除" }).click();
  await screen.getByRole("button", { name: "削除する" }).click();

  await expect
    .element(screen.getByRole("alert"))
    .toHaveTextContent("対象の API キーが見つかりませんでした");
});

